import azure.functions as func
from azure.storage.blob import BlobServiceClient
import os
import sys
import urllib.parse

def main(req: func.HttpRequest) -> func.HttpResponse:
    # Get the blob path from query parameters
    blob_path = req.params.get('blobPath')

    if not blob_path:
        return func.HttpResponse(
            "Please pass a blobPath on the query string or form data.",
            status_code=400
        )

    # Parse query parameter to URL-safe format
    parsed_path = urllib.parse.unquote(blob_path)
    
    try:
        # Get the account name and key from environment variables
        account_name = os.environ['AZURE_STORAGE_ACCOUNT']
        account_key = os.environ['AZURE_STORAGE_ACCESS_KEY']

        # Create a BlobServiceClient object with the given credentials
        blob_service_client = BlobServiceClient.from_connection_string(
            f"DefaultEndpointsProtocol=https;AccountName={account_name};AccountKey={account_key}"
        )

        # Get a reference to the container and a blob client for the container
        container_client = blob_service_client.get_container_client(parsed_path.split('/')[0])
        
        if not container_client.exists():
            return func.HttpResponse(
                "Container does not exist.",
                status_code=404
            )
        
        # Create a blob client object for the given blob name within the container
        blob_client = blob_service_client.get_blob_client(parsed_path)

        # Download file from Blob Storage
        blob_data = blob_client.download_blob()
        return func.HttpResponse(
            body=blob_data.content_as_text(),
            mimetype='application/octet-stream'
        )

    except Exception as e:
        print(f"An error occurred: {e}")
        return func.HttpResponse(
            f"An unexpected error occurred.",
            status_code=500
        )